.agro-hero {
  background: linear-gradient(135deg, #fdfcf7 0%, #f9f6ed 100%);
  border-radius: 12px;
  padding: 32px 24px;
  margin: 16px 0;
  position: relative;
  overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
}

.agro-hero::before {
  content: '';
  position: absolute;
  top: -40%;
  right: -15%;
  width: 400px;
  height: 400px;
  background: radial-gradient(circle, rgba(212, 167, 44, 0.08) 0%, transparent 70%);
  border-radius: 50%;
  pointer-events: none;
}

.agro-container {
  display: flex;
  gap: 32px;
  align-items: flex-start;
  max-width: 1100px;
  margin: 0 auto;
  position: relative;
  z-index: 1;
}

/* MAIN CONTENT */
.agro-main {
  flex: 1;
}

.agro-badge {
  display: inline-block;
  background: linear-gradient(135deg, #2C8063 0%, #2D5F3F 100%);
  color: white;
  padding: 6px 16px;
  border-radius: 20px;
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 16px;
  box-shadow: 0 3px 10px rgba(44, 128, 99, 0.25);
}

.agro-title {
  font-size: 34px;
  line-height: 1.25;
  color: #000;
  margin: 0 0 12px 0;
  font-weight: 700;
}

.agro-brand {
  color: #D4A72C;
  font-weight: 800;
  font-size: 36px;
}

.agro-highlight {
  color: #2C8063;
  font-weight: 800;
}

.agro-desc {
  font-size: 15px;
  color: #3d5a47;
  line-height: 1.5;
  margin: 0 0 20px 0;
}

.agro-features {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.agro-features span {
  background: white;
  padding: 8px 14px;
  border-radius: 6px;
  font-size: 13px;
  color: #2D5F3F;
  font-weight: 600;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
  border: 1px solid #e8dcc4;
}

/* SIDEBAR */
.agro-sidebar {
  flex: 0 0 280px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

/* STATS */
.agro-stats {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  background: white;
  padding: 20px 16px;
  border-radius: 10px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  border-left: 4px solid #D4A72C;
}

.agro-stat {
  text-align: center;
}

.agro-stat strong {
  display: block;
  font-size: 28px;
  color: #D4A72C;
  font-weight: 800;
  margin-bottom: 2px;
}

.agro-stat span {
  font-size: 12px;
  color: #616161;
  font-weight: 500;
}

/* CTA */
.agro-cta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: linear-gradient(135deg, #D4A72C 0%, #b8921f 100%);
  color: white;
  padding: 14px 20px;
  border-radius: 10px;
  font-size: 17px;
  font-weight: 700;
  text-decoration: none;
  box-shadow: 0 4px 16px rgba(212, 167, 44, 0.35);
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
}

.agro-cta::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.25), transparent);
  transition: left 0.5s;
}

.agro-cta:hover::before {
  left: 100%;
}

.agro-cta:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(212, 167, 44, 0.45);
  color: white;
  text-decoration: none;
}

.agro-badge-live {
  background: white;
  color: #D4A72C;
  padding: 4px 10px;
  border-radius: 12px;
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 0.5px;
}

.agro-note {
  display: block;
  text-align: center;
  font-size: 12px;
  color: #757575;
  font-style: italic;
  margin-top: -8px;
}

/* RESPONSIVE */
@media (max-width: 900px) {
  .agro-container {
    flex-direction: column;
    gap: 24px;
  }

  .agro-sidebar {
    flex: 1;
    width: 100%;
  }

  .agro-title {
    font-size: 28px;
  }

  .agro-brand {
    font-size: 30px;
  }
}

@media (max-width: 640px) {
  .agro-hero {
    padding: 24px 16px;
  }

  .agro-title {
    font-size: 24px;
  }

  .agro-brand {
    font-size: 26px;
  }

  .agro-features {
    flex-direction: column;
  }
}
